import bisect

class Solution(object):
    def minAbsoluteDifference(self, nums, x):
        n = len(nums)
        # For each j >= x, find the closest value in nums[0..j-x] using a sorted list.
        sorted_left = []
        ans = float('inf')

        for j in range(n):
            # Add nums[j - x] to sorted_left when j >= x
            if j >= x:
                bisect.insort(sorted_left, nums[j - x])
                # Find closest to nums[j]
                v = nums[j]
                idx = bisect.bisect_left(sorted_left, v)
                if idx < len(sorted_left):
                    ans = min(ans, sorted_left[idx] - v)
                if idx > 0:
                    ans = min(ans, v - sorted_left[idx - 1])

        return ans
